import { useState, useRef } from 'react';
import { useAuth } from '../../context/AuthContext';

const TRIMESTERS = [
  { value: 1, label: '1st Trimester', emoji: '🌱', weeks: 'Weeks 1–12' },
  { value: 2, label: '2nd Trimester', emoji: '🌷', weeks: 'Weeks 13–26' },
  { value: 3, label: '3rd Trimester', emoji: '🌸', weeks: 'Weeks 27–40' },
];

const s = {
  overlay: {
    position: 'fixed', inset: 0,
    background: 'rgba(44,62,80,0.45)',
    backdropFilter: 'blur(4px)',
    zIndex: 1000,
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    padding: 24, animation: 'fadeIn 0.2s ease',
  },
  modal: {
    background: 'var(--white)', borderRadius: 'var(--radius-xl)',
    width: '100%', maxWidth: 520,
    maxHeight: '90vh', overflowY: 'auto',
    boxShadow: '0 24px 80px rgba(44,62,80,0.25)',
    animation: 'bounceIn 0.35s cubic-bezier(.36,.07,.19,.97) both',
  },
  header: {
    padding: '28px 32px 20px',
    borderBottom: '1px solid var(--border)',
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
  },
  headerTitle: {
    fontFamily: 'var(--font-display)', fontSize: 22,
    fontWeight: 600, color: 'var(--slate)',
  },
  closeBtn: {
    width: 34, height: 34, borderRadius: '50%',
    background: 'var(--blush)', border: '1px solid var(--border)',
    cursor: 'pointer', fontSize: 16, display: 'flex',
    alignItems: 'center', justifyContent: 'center',
  },
  body: { padding: '24px 32px 32px' },
  avatarSection: {
    display: 'flex', alignItems: 'center', gap: 20, marginBottom: 28,
    padding: '18px 20px', background: 'var(--blush)',
    borderRadius: 'var(--radius-md)', border: '1px solid var(--border)',
  },
  avatarCircle: {
    width: 72, height: 72, borderRadius: '50%',
    background: 'linear-gradient(135deg, var(--rose), var(--rose-dark))',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontSize: 30, flexShrink: 0, overflow: 'hidden',
    border: '3px solid var(--white)',
    boxShadow: '0 4px 12px rgba(232,102,122,0.3)',
  },
  uploadBtn: {
    padding: '8px 18px', borderRadius: 99,
    border: '1.5px solid var(--rose)', background: 'var(--rose-light)',
    color: 'var(--rose-dark)', fontSize: 12, fontWeight: 600,
    cursor: 'pointer', transition: 'all 0.2s ease',
    fontFamily: 'var(--font-body)', letterSpacing: '0.02em',
  },
  avatarHint: { fontSize: 11, color: 'var(--slate-light)', marginTop: 4 },
  section: { marginBottom: 24 },
  sectionTitle: {
    fontSize: 11, fontWeight: 700, color: 'var(--slate-mid)',
    letterSpacing: '0.08em', textTransform: 'uppercase',
    marginBottom: 14, paddingBottom: 8,
    borderBottom: '1px solid var(--border)',
  },
  row2: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 },
  fieldWrap: { marginBottom: 14 },
  label: {
    display: 'block', fontSize: 12, fontWeight: 600,
    color: 'var(--slate-mid)', letterSpacing: '0.04em',
    textTransform: 'uppercase', marginBottom: 6,
  },
  input: (focused) => ({
    width: '100%', padding: '10px 14px',
    borderRadius: 'var(--radius-sm)',
    border: `1.5px solid ${focused ? 'var(--rose)' : 'var(--border)'}`,
    background: focused ? 'var(--blush)' : 'var(--cream)',
    fontSize: 14, color: 'var(--slate)', outline: 'none',
    fontFamily: 'var(--font-body)', transition: 'all 0.2s ease',
    boxShadow: focused ? '0 0 0 3px rgba(232,102,122,0.1)' : 'none',
  }),
  trimRow: { display: 'flex', gap: 8 },
  trimBtn: (selected) => ({
    flex: 1, padding: '10px 8px', borderRadius: 10,
    border: `2px solid ${selected ? 'var(--rose)' : 'var(--border)'}`,
    background: selected ? 'var(--rose-light)' : 'var(--cream)',
    cursor: 'pointer', textAlign: 'center', transition: 'all 0.2s ease',
    fontFamily: 'var(--font-body)',
  }),
  trimBtnEmoji: { fontSize: 18, display: 'block', marginBottom: 3 },
  trimBtnLabel: (selected) => ({
