    borderRadius: 'var(--radius-md)',
    background: loading ? 'var(--rose-mid)' : 'linear-gradient(135deg, var(--rose) 0%, var(--rose-dark) 100%)',
    color: '#fff', border: 'none', cursor: loading ? 'not-allowed' : 'pointer',
    fontSize: 14, fontWeight: 600, transition: 'all 0.2s ease',
    fontFamily: 'var(--font-body)', letterSpacing: '0.03em',
    boxShadow: loading ? 'none' : '0 4px 16px rgba(232,102,122,0.3)',
    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
